1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	const HIGH_ENCHANTMENT_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	
10	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	type Item = {
18	  type: string;
19	  material?: string;
20	  enchantment?: number;
21	  cursed?: boolean;
22	};
23	type Step = { op: "quote"; items: Item[] };
24	type Scenario = { customer: unknown; steps: Step[] };
25	
26	const componentGroupPremium = (count: number): number =>
27	  count === COMPONENT_BLOCK_SIZE
28	    ? COMPONENT_BLOCK_PREMIUM
29	    : count * COMPONENT_BASE_PREMIUM;
30	
31	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
32	
33	const isHighEnchantment = (item: Item): boolean =>
34	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
35	
36	const surchargeRates = (item: Item, applyFirstInsurance: boolean): number[] => [
37	  item.cursed ? CURSE_SURCHARGE_RATE : 0,
38	  isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0,
39	  applyFirstInsurance && item.cursed && !isHighEnchantment(item) ? FIRST_INSURANCE_RATE : 0,
40	];
41	
42	const mainItemPremium = (item: Item, applyFirstInsurance: boolean): number => {
43	  const base = BASE_PREMIUM_BY_TYPE[item.type];
44	  const totalRate = surchargeRates(item, applyFirstInsurance).reduce((a, b) => a + b, 1);
45	  return base * totalRate;
46	};
47	
48	const countByType = (items: Item[]): Map<string, number> =>
49	  items.reduce(
50	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
51	    new Map<string, number>(),
52	  );
53	
54	const sumComponentPremiums = (components: Item[]): number =>
55	  [...countByType(components).values()]
56	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
57	
58	const sumItemPremiums = (items: Item[]): number => {
59	  const mains = items.filter(isMainItem);
60	  const components = items.filter((i) => !isMainItem(i));
61	  const applyFirstInsurance = items.length === 1;
62	  const mainsSum = mains.reduce((sum, item) => sum + mainItemPremium(item, applyFirstInsurance), 0);
63	  return mainsSum + sumComponentPremiums(components);
64	};
65	
66	const quotePremiumFor = (step: Step): { premium: number } => ({
67	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
68	});
69	
70	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
71	  results: scenario.steps.map(quotePremiumFor),
72	});
